// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Map weather conditions to emoji icons
  const getWeatherEmoji = useCallback((condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sun') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog')) return '🌫️';
    return '🌤️';
  }, []);

  return {
    getWeatherEmoji,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        {/* Main Weather Card */}
        <Card shadow="md" padding={24} radius="lg">
          <Stack gap={16} align="center">
            {/* City Name and Condition */}
            <Stack gap={8} align="center">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>

            {/* Weather Icon - Large */}
            <Box padding={16} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={12}>
              <Text size="4xl" align="center">
                {state.getWeatherEmoji(props.condition)}
              </Text>
            </Box>

            {/* Current Temperature - Large and Prominent */}
            <Stack gap={4} align="center">
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {props.temperature}°{props.unit}
              </Text>
            </Stack>

            {/* Divider */}
            <Divider margin={8} />

            {/* Humidity and Wind Speed */}
            <Stack direction="horizontal" gap={24} justify="center" align="center" wrap>
              <Box padding={12}>
                <Stack gap={4} align="center">
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    💧 Humidity
                  </Text>
                  <Text
                    size="lg"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {props.humidity}%
                  </Text>
                </Stack>
              </Box>
              <Box padding={12}>
                <Stack gap={4} align="center">
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    💨 Wind Speed
                  </Text>
                  <Text
                    size="lg"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {props.windSpeed} m/s
                  </Text>
                </Stack>
              </Box>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Stack gap={8}>
          <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">5-Day Forecast</Heading>
          <Stack direction="horizontal" gap={8} wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding={12}
                  radius="md"
                  border={true}
                  style={{ flex: '1 1 auto', minWidth: '100px' }}
                >
                  <Stack gap={8} align="center" justify="center">
                    {/* Day Name */}
                    {day.day && (
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        align="center"
                      >
                        {day.day}
                      </Text>
                    )}

                    {/* Day Icon/Emoji */}
                    {day.icon && (
                      <Text size="2xl" align="center">
                        {day.icon}
                      </Text>
                    )}

                    {/* High/Low Temps */}
                    {(day.high !== undefined || day.low !== undefined) && (
                      <Stack gap={2} align="center">
                        {day.high !== undefined && (
                          <Text
                            variant="caption"
                            weight="semibold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {day.high}°{props.unit}
                          </Text>
                        )}
                        {day.low !== undefined && (
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            {day.low}°{props.unit}
                          </Text>
                        )}
                      </Stack>
                    )}
                  </Stack>
                </Card>
              ))
            ) : (
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                No forecast data available
              </Text>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit: (data: ActionSubmitPayload) => void; // Called with all collected answers
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  // Actions — fire-and-forget to agent (removed unused useAction import)

  // Form state
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isValidEmail = email === '' || emailRegex.test(email);
  const isNameValid = name.trim() !== '';
  const isStep1Valid = isNameValid && isValidEmail && email.trim() !== '';
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = features.length > 0;

  // Navigation
  const handleNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) return;
    if (step === 2 && !isStep2Valid) return;
    if (step === 3 && !isStep3Valid) return;
    if (step < 5) {
      setStep(step + 1);
    }
  }, [step, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  const handleSubmit = useCallback((onSubmitFn: (data: ActionSubmitPayload) => void) => {
    onSubmitFn({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim()
    });
  }, [name, email, satisfaction, features, comments]);

  // Feature toggle handler
  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures(prev =>
      prev.includes(feature)
        ? prev.filter(f => f !== feature)
        : [...prev, feature]
    );
  }, []);

  return {
    step,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    handleFeatureToggle,
    comments,
    setComments,
    handleNext,
    handleBack,
    handleSubmit: (fn: (data: ActionSubmitPayload) => void) => state.handleSubmit(fn),
    isStep1Valid,
    isStep2Valid,
    isStep3Valid,
    isValidEmail
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const satisfactionOptions = props.satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label: `${idx + 1} - ${label}`
  }));

  return (
    <Container maxWidth="lg" padding={24} center>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={1}>Survey Form</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {state.step} of 4
          </Text>
          <Progress
            value={state.step}
            max={4}
            variant="default"
            size="md"
            showLabel={false}
          />
        </Stack>

        {/* Step 1: Name & Email */}
        {state.step === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Full Name"
                value={state.name}
                onChange={state.setName}
                placeholder="John Doe"
                required
              />
              <Input
                label="Email Address"
                type="email"
                value={state.email}
                onChange={state.setEmail}
                placeholder="john@example.com"
                required
                error={state.email !== '' && !state.isValidEmail ? 'Please enter a valid email' : ''}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.step === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.step === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Which Features Interest You?</Heading>
              <Stack gap={12}>
                {props.featureOptions.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {state.step === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments (Optional)"
                value={state.comments}
                onChange={state.setComments}
                placeholder="Share any additional feedback..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {state.step === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={20}>
              <Heading level={3}>Review Your Answers</Heading>

              <Box
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                padding={16}
                borderRadius={8}
              >
                <Stack gap={12}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Name
                    </Text>
                    <Text variant="body">{state.name}</Text>
                  </Stack>
                  <Divider margin={8} />

                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email
                    </Text>
                    <Text variant="body">{state.email}</Text>
                  </Stack>
                  <Divider margin={8} />

                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body">
                      {state.satisfaction ? `${state.satisfaction} - ${props.satisfactionLabels[parseInt(state.satisfaction, 10) - 1]}` : 'N/A'}
                    </Text>
                  </Stack>
                  <Divider margin={8} />

                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Interested Features
                    </Text>
                    <Stack gap={6} direction="horizontal" wrap>
                      {state.features.map(feature => (
                        <Badge key={feature} variant="primary" size="md">
                          {feature}
                        </Badge>
                      ))}
                    </Stack>
                  </Stack>
                  <Divider margin={8} />

                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Comments
                    </Text>
                    <Text variant="body">
                      {state.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap={12} justify="between" align="center">
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.step === 1}
          >
            Back
          </Button>

          <Stack direction="horizontal" gap={8}>
            {state.step < 5 && (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={
                  (state.step === 1 && !state.isStep1Valid) ||
                  (state.step === 2 && !state.isStep2Valid) ||
                  (state.step === 3 && !state.isStep3Valid)
                }
              >
                Next
              </Button>
            )}
            {state.step === 5 && (
              <Button
                variant="primary"
                onClick={() => state.handleSubmit(props.onSubmit)}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action', { detail: { name: 'taskUpdate', payload } }));
  };

  // Streams — real-time from agent (.latest, .all)
  const [taskChangedData, setTaskChangedData] = useState<StreamTaskChanged | null>(null);
  const taskChanged = { latest: taskChangedData, all: [taskChangedData].filter(Boolean) as StreamTaskChanged[] };

  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Listen for stream events and update tasks in real-time
  useEffect(() => {
    const handleStreamEvent = (event: Event) => {
      const customEvent = event as CustomEvent<{ name: string; data: StreamTaskChanged }>;
      if (customEvent.detail.name === 'taskChanged') {
        setTaskChangedData(customEvent.detail.data);
      }
    };
    window.addEventListener('ggui:agent-data', handleStreamEvent as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleStreamEvent as EventListener);
  }, []);

  // Update tasks when props change or stream events arrive
  useEffect(() => {
    if (taskChangedData?.task) {
      const updated = taskChangedData.task;
      setTasks((prev) => {
        const filtered = prev.filter((t) => t.id !== updated.id);
        if (taskChangedData?.action !== 'delete') {
          filtered.push(updated);
        }
        return filtered;
      });
    }
  }, [taskChangedData]);

  // Compute tasks per column
  const tasksByColumn = React.useMemo(() => {
    const byCol: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      byCol[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const col = task.column || 'todo';
      if (!byCol[col]) byCol[col] = [];
      byCol[col].push(task);
    });
    return byCol;
  }, [tasks, props.columns]);

  // Summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasksByColumn['done']?.length || 0;

  // Move task to column
  const handleMoveTask = useCallback(
    (taskId: string, toColumn: string) => {
      const task = tasks.find((t) => t.id === taskId);
      if (!task) return;

      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
    },
    [tasks, taskUpdate]
  );

  // Start editing task
  const handleStartEdit = useCallback((taskId: string) => {
    const task = tasks.find((t) => t.id === taskId);
    if (task) {
      setEditingTaskId(taskId);
      setEditTitle(task.title || '');
    }
  }, [tasks]);

  // Save edited task
  const handleSaveEdit = useCallback(
    (taskId: string) => {
      if (!editTitle.trim()) return;
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: editTitle } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { title: editTitle, column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
      setEditingTaskId(null);
      setEditTitle('');
    },
    [editTitle, tasks, taskUpdate]
  );

  // Add new task
  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  return {
    tasks,
    setTasks,
    tasksByColumn,
    totalTasks,
    completedTasks,
    editingTaskId,
    setEditingTaskId,
    editTitle,
    setEditTitle,
    showAddForm,
    setShowAddForm,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    handleMoveTask,
    handleStartEdit,
    handleSaveEdit,
    handleAddTask,
    taskUpdate,
    taskChanged,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="md" radius="lg">
          <Stack direction="horizontal" gap={24} align="center">
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label">Tasks:</Text>
              <Badge variant="primary" size="md">{state.totalTasks}</Badge>
            </Stack>
            <Divider orientation="vertical" />
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label">Completed:</Text>
              <Badge variant="success" size="md">{state.completedTasks}</Badge>
            </Stack>
            <Spacer size="flex" />
            <Progress
              value={state.totalTasks > 0 ? (state.completedTasks / state.totalTasks) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              showLabel={false}
            />
          </Stack>
        </Card>

        {/* Kanban Board */}
        <Row gap={16} wrap>
          {props.columns.map((column) => {
            const colTasks = state.tasksByColumn[column.id || ''] || [];
            return (
              <Box
                key={column.id}
                style={{
                  flex: '0 0 calc(33.333% - 12px)',
                  minWidth: '300px',
                  display: 'flex',
                  flexDirection: 'column',
                }}
              >
                <Card padding={0} shadow="sm" radius="lg" border>
                  <Stack gap={0}>
                    {/* Column Header */}
                    <Box
                      paddingX={16}
                      paddingY={12}
                      background="var(--ggui-color-primary-50, #f0f9ff)"
                      borderRadius={0}
                      style={{
                        borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                      }}
                    >
                      <Stack direction="horizontal" gap={8} justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-primary-900, #0c4a6e)">
                          {column.name}
                        </Text>
                        <Badge variant="primary" size="sm">
                          {colTasks.length}
                        </Badge>
                      </Stack>
                    </Box>

                    {/* Task List */}
                    <Box paddingX={12} paddingY={12} style={{ minHeight: '200px' }}>
                      <Stack gap={8}>
                        {colTasks.map((task) => {
                          const isEditing = state.editingTaskId === task.id;
                          const priorityVariant =
                            task.priority === 'high'
                              ? 'error'
                              : task.priority === 'medium'
                              ? 'warning'
                              : 'success';

                          return (
                            <Card
                              key={task.id}
                              padding={12}
                              shadow="sm"
                              radius="md"
                              border
                              as={Clickable}
                              style={{
                                cursor: 'grab',
                                transition: 'all 200ms ease-in-out',
                              }}
                            >
                              <Stack gap={8}>
                                {/* Task Title */}
                                {isEditing ? (
                                  <Stack direction="horizontal" gap={4}>
                                    <Input
                                      label="Edit title"
                                      value={state.editTitle}
                                      onChange={state.setEditTitle}
                                      size="sm"
                                      type="text"
                                    />
                                    <Button
                                      variant="primary"
                                      size="xs"
                                      onClick={() => state.handleSaveEdit(task.id || '')}
                                    >
                                      Save
                                    </Button>
                                    <Button
                                      variant="ghost"
                                      size="xs"
                                      onClick={() => state.setEditingTaskId(null)}
                                    >
                                      Cancel
                                    </Button>
                                  </Stack>
                                ) : (
                                  <Stack
                                    direction="horizontal"
                                    gap={8}
                                    justify="between"
                                    align="start"
                                    as={Clickable}
                                    onClick={() => {
                                      if (state.editingTaskId !== task.id) {
                                        state.handleStartEdit(task.id || '');
                                      }
                                    }}
                                    onDoubleClick={() => state.handleStartEdit(task.id || '')}
                                    style={{ userSelect: 'none' }}
                                  >
                                    <Text
                                      variant="body"
                                      style={{
                                        flex: 1,
                                        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                                      }}
                                    >
                                      {task.title}
                                    </Text>
                                    <Button
                                      variant="ghost"
                                      size="xs"
                                      onClick={(e) => {
                                        e.stopPropagation();
                                        state.handleStartEdit(task.id || '');
                                      }}
                                    >
                                      <Icon name="edit-2" size={14} />
                                    </Button>
                                  </Stack>

                                {/* Priority Badge */}
                                {task.priority && (
                                  <Badge
                                  <Badge
                                    variant={priorityVariant as any}
                                    size="sm"
                                    pill
                                  >
                                    {task.priority}
                                  </Badge>
                                )}

                                {/* Assignee & Due Date */}
                                <Stack direction="horizontal" gap={8} align="center">
                                  {task.assignee && (
                                    <Avatar
                                      name={task.assignee}
                                      size="sm"
                                      shape="circle"
                                    />
                                  )}
                                  {task.dueDate && (
                                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                      Due: {task.dueDate}
                                    </Text>
                                  )}
                                </Stack>

                                {/* Move Dropdown */}
                                <Dropdown
                                  trigger={
                                    <Button variant="outline" size="xs" fullWidth>
                                      Move to...  <Icon name="chevron-down" size={12} />
                                    </Button>
                                  }
                                  options={props.columns
                                    .filter((c) => c.id !== column.id)
                                    .map((c) => ({
                                      value: c.id || '',
                                      label: c.name || '',
                                    }))}
                                  value=""
                                  onChange={(val) => state.handleMoveTask(task.id || '', val)}
                                  placement="bottom-end"
                                />
                              </Stack>
                            </Card>
                          );
                        })}
                      </Stack>
                    </Box>

                    {/* Add Task Form */}
                    <Box paddingX={12} paddingY={8}>
                      {state.showAddForm === column.id ? (
                        <Stack gap={8}>
                          <Input
                            label="Task title"
                            value={state.newTaskTitle}
                            onChange={state.setNewTaskTitle}
                            placeholder="Enter task title"
                            size="sm"
                          />
                          <Select
                            label="Priority"
                            value={state.newTaskPriority}
                            onChange={(val) => state.setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                            size="sm"
                          />
                          <Stack direction="horizontal" gap={8}>
                            <Button
                              variant="primary"
                              size="xs"
                              onClick={() => state.handleAddTask(column.id || '')}
                              fullWidth
                            >
                              Add
                            </Button>
                            <Button
                              variant="ghost"
                              size="xs"
                              onClick={() => state.setShowAddForm(null)}
                              fullWidth
                            >
                              Cancel
                            </Button>
                          </Stack>
                        </Stack>
                      ) : (
                        <Button
                          variant="ghost"
                          size="sm"
                          fullWidth
                          onClick={() => state.setShowAddForm(column.id || '')}
                        >
                          <Icon name="plus" size={16} /> Add Task
                        </Button>
                      )}
                    </Box>
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
